47	/// first item to `{index}-in.{tag}.{ext}` files in `dir`. Returns the
48	/// filenames written (empty if the pasteboard has no items or we are not on
49	/// macOS). Errors are logged via `apcrl_error_now!` at the FFI boundary
50	/// before being returned so the caller can decide on fallback without
51	/// losing the diagnostic detail.
52	#[cfg(target_os = "macos")]
53	pub fn apcrb_capture_declared_flavors(
54	    dir:            &Path,
55	    classification: apcrh_Classification,
56	    index:          u32,
57	) -> Result<Vec<String>, String> {
58	    fs::create_dir_all(dir)
59	        .map_err(|e| {
60	            let msg = format!("create harvest dir {}: {}", dir.display(), e);
61	            crate::apcrl_error_now!("apcrb: {}", msg);
62	            msg
63	        })?;
64	
65	    let tag = classification.apcrh_tag();
66	    let pasteboard = NSPasteboard::generalPasteboard();
67	
68	    let items = match pasteboard.pasteboardItems() {
69	        Some(items) => items,
70	        None        => {
71	            crate::apcrl_error_now!("apcrb: pasteboardItems returned nil");
72	            return Err("pasteboardItems nil".to_string());
73	        }
74	    };
75	
76	    // By Apple convention the first item is the producer's primary write.
77	    // Copy All from Epic produces exactly one item; enumerating beyond it
78	    // invites macOS-synthesized derivatives we've explicitly scoped out.
79	    // If the pasteboard has zero items â€” despite arboard in the classifier
80	    // path having successfully read text from it moments ago â€” that is a
81	    // genuine disagreement worth surfacing, not a soft success.
82	    let first_item = match items.iter().next() {
83	        Some(item) => item,
84	        None       => {
85	            crate::apcrl_error_now!("apcrb: pasteboard has 0 items");
86	            return Err("pasteboard has 0 items".to_string());
87	        }
88	    };
89	
90	    let types = first_item.types();
91	    let mut filenames: Vec<String> = Vec::new();
92	
93	    for uti in types.iter() {
94	        let uti_str = uti.to_string();
95	
96	        let data = match first_item.dataForType(&uti) {
97	            Some(d) => d,
98	            None    => {
99	                crate::apcrl_error_now!(
100	                    "apcrb: dataForType({}) returned nil â€” declared but empty",
101	                    uti_str
102	                );
103	                continue;
104	            }
105	        };
106	
107	        let ext = apcrb_extension_for_uti(&uti_str);
108	        let filename = format!("{}-in.{}.{}", index, tag, ext);
109	        let path = dir.join(&filename);
110	
111	        let bytes = data.to_vec();
112	        let mut file = match fs::File::create(&path) {
113	            Ok(f)  => f,
114	            Err(e) => {
115	                let msg = format!("create {}: {}", path.display(), e);
116	                crate::apcrl_error_now!("apcrb: {}", msg);
117	                return Err(msg);
118	            }
119	        };
120	        if let Err(e) = file.write_all(&bytes) {
121	            let msg = format!("write {} ({} bytes): {}", path.display(), bytes.len(), e);
122	            crate::apcrl_error_now!("apcrb: {}", msg);
123	            return Err(msg);
124	        }
125	
126	        crate::apcrl_info_now!(
127	            "apcrb: wrote {} ({} bytes, uti={})",
128	            filename, bytes.len(), uti_str
129	        );
130	        filenames.push(filename);
131	    }
