15	//! Clipboard harvest â€” capture every **declared** clipboard flavor
16	//! verbatim to `{N}-in.{tag}.{ext}` files in the journal directory
17	//! (typically `$HOME/apcjd/`) on every focus with changed content. The
18	//! `tag` is the classifier's verdict (`clinical` or `nonclinical`); the
19	//! full filename is e.g. `10000-in.clinical.rtf`,
20	//! `10000-in.clinical.utf8.txt`, `10000-in.nonclinical.utf8.txt`.
21	//!
22	//! Enumeration is delegated to `apcrb_pasteboard`
23	//! (`apcrb_capture_declared_flavors`), which reads NSPasteboard directly
24	//! on macOS. There is no alternate capture path â€” a failure in `apcrb`
25	//! (FFI error, non-macOS build, empty pasteboard) surfaces as an `Err`
26	//! that the caller logs via `apcrl_error_now!` and leaves the focus
27	//! cycle without an artifact on disk. Making failure visible beats
28	//! silently duplicating arboard work the classifier already did.
29	//!
30	//! On the Clinical branch, the focus handler pairs each capture with a
31	//! `{N}-out.txt` anonymized copy written by `apcap_main`. PHI-at-rest
32	//! stays outside the repo; anonymization and promotion to test fixtures
33	//! are manual. The destination is supplied by the caller; see
34	//! `apcrj_journal::apcrj_journal_path`. This module does not emit â€”
35	//! errors are returned to the caller for routing via `apcrl_*`;
36	//! `apcrb_pasteboard` logs its own FFI diagnostics at the boundary.
37	
38	use std::fs;
39	use std::path::Path;
40	
41	pub const APCRH_HARVEST_SEED_INDEX: u32 = 10000;
42	
43	/// Classifier verdict used to tag harvest filenames. The tag is decided by
44	/// the caller *before* harvest runs, not inferred from filename later.
45	#[derive(Copy, Clone, Debug, PartialEq, Eq)]
46	pub enum apcrh_Classification {
47	    Clinical,
48	    NonClinical,
49	}
50	
51	impl apcrh_Classification {
52	    /// Filename infix written between `-in.` and the extension.
53	    pub fn apcrh_tag(self) -> &'static str {
54	        match self {
55	            apcrh_Classification::Clinical    => "clinical",
56	            apcrh_Classification::NonClinical => "nonclinical",
57	        }
58	    }
59	}
60	
61	/// Capture every **declared** clipboard flavor into `{N}-in.{tag}.{ext}`
62	/// files in `dir`, where `tag` is `classification`'s filename infix.
63	/// Returns the N used. N seeds at `APCRH_HARVEST_SEED_INDEX` when `dir` is
64	/// empty, otherwise `max_leading_digit_run + 1` across any filenames that
65	/// begin with digits (legacy bare `{N}.{ext}`, prior `{N}-in.{ext}`,
66	/// `{N}-out.{ext}`, new `{N}-in.{tag}.{ext}`, and multi-flavor
67	/// `{N}-in.{tag}.rtf` / `{N}-in.{tag}.utf8.txt` all count). The directory
68	/// is created lazily.
69	///
70	/// Enumeration is delegated to `apcrb_pasteboard`. An error from `apcrb`
71	/// is propagated â€” harvest does not synthesize a fallback capture. The
72	/// caller (`apcap_main`) logs the failure and continues triage; absence
73	/// of a `{N}-in.{tag}.*` file on disk is the visible signal that the
74	/// NSPasteboard path failed.
75	pub fn apcrh_capture_all_flavors(
76	    dir: &Path,
77	    classification: apcrh_Classification,
78	) -> Result<u32, String> {
79	    fs::create_dir_all(dir)
80	        .map_err(|e| format!("create harvest dir {}: {}", dir.display(), e))?;
81	
82	    let index = zapcrh_scan_next_index(dir)?;
83	
84	    crate::apcrb_pasteboard::apcrb_capture_declared_flavors(
85	        dir, classification, index,
86	    )?;
87	
88	    Ok(index)
89	}
90	
91	/// Scan `dir` for files whose name begins with a digit run and return
92	/// `max+1`, or `APCRH_HARVEST_SEED_INDEX` when none are found. Files whose
93	/// name does not start with a digit (e.g. `apcap.log`, `README`) are
94	/// ignored, as are subdirectories. Gaps are not filled â€” the scan advances
95	/// past the current maximum. The leading-digit parse makes mixed naming
96	/// styles â€” legacy bare `{N}.{ext}`, prior `{N}-in.{ext}`, `{N}-out.{ext}`,
97	/// and new `{N}-in.{tag}.{ext}` â€” all count toward the same index space.
98	pub(crate) fn zapcrh_scan_next_index(dir: &Path) -> Result<u32, String> {
99	    let entries = fs::read_dir(dir)
100	        .map_err(|e| format!("read harvest dir {}: {}", dir.display(), e))?;
101	
102	    let mut max: Option<u32> = None;
103	    for entry in entries {
104	        let entry = entry
105	            .map_err(|e| format!("read harvest entry: {}", e))?;
106	        if !entry.file_type().map(|t| t.is_file()).unwrap_or(false) {
107	            continue;
108	        }
109	        let path = entry.path();
110	        let name = match path.file_name().and_then(|s| s.to_str()) {
111	            Some(s) => s,
112	            None    => continue,
113	        };
114	        let digits: String = name.chars().take_while(|c| c.is_ascii_digit()).collect();
115	        if digits.is_empty() {
116	            continue;
117	        }
118	        if let Ok(n) = digits.parse::<u32>() {
119	            max = Some(max.map_or(n, |m| m.max(n)));
120	        }
121	    }
122	
123	    Ok(match max {
124	        Some(n) => n.saturating_add(1),
125	        None    => APCRH_HARVEST_SEED_INDEX,
126	    })
127	}
